{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires separating the probabilistic modeling of polyomino locations from the sequential decision-making process of selecting probe locations.",
  "helpers": [
    {
      "label": "probabilistic_map_estimator",
      "instructions": "Maintain a probability distribution over all possible valid placements of the known polyomino shapes on the grid. Given a set of previous query results (drilling outcomes or noisy aggregate counts), update the posterior probability for each cell being part of an oil field using Bayesian inference."
    },
    {
      "label": "information_gain_optimizer",
      "instructions": "Given the current probability map, evaluate potential probe locations (drilling or aggregate queries). Calculate the expected reduction in entropy or the expected information gain for each query type, accounting for the noise model in the aggregate queries."
    },
    {
      "label": "cost_benefit_planner",
      "instructions": "Implement a decision policy that selects the next action by balancing the cost of the probe against the expected reduction in uncertainty. This should decide whether to perform a high-precision drill, a low-cost noisy aggregate query, or to stop probing and submit a final guess based on the current confidence levels."
    },
    {
      "label": "final_guess_generator",
      "instructions": "Once the probing budget is exhausted or the uncertainty threshold is met, identify the set of cells with the highest marginal probability of containing oil to form the final answer."
    }
  ],
  "synthesis_brief": "The parent will use the probabilistic_map_estimator to track the state of the grid, pass that state to the information_gain_optimizer to rank potential actions, use the cost_benefit_planner to execute the sequence of probes, and finally call the final_guess_generator to produce the output."
}

